/**
 * Notification log model — records of sent notifications for history tracking.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/** Delivery status of a notification log entry. */
export type DeliveryStatus = 'sent' | 'failed' | 'pending';

/** A persisted record of a notification that was processed. */
export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  status: DeliveryStatus;
  timestamp: Date;
  error?: string;
  metadata?: Record<string, unknown>;
}

/** Query filter for retrieving notification history. */
export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      status: record['status'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
      error: record['error'] as string | undefined,
      metadata: record['metadata']
        ? JSON.parse(record['metadata'] as string) as Record<string, unknown>
        : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      status: entity.status,
      timestamp: entity.timestamp.toISOString(),
      error: entity.error,
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.timestamp >= startDate && log.timestamp <= endDate,
    );
  }
}

/**
 * Notification history service — tracks and queries sent notification history.
 *
 * Provides logging of every notification processed by the NotificationService
 * and query capabilities for retrieving notification history.
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { Notification } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset ID counter (for testing). */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Record a notification in the history log.
   */
  record(notification: Notification): NotificationLog {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      status: notification.status,
      timestamp: notification.sentAt ?? notification.createdAt,
      error: notification.error,
      metadata: notification.metadata,
    };

    this.logger.info(
      `Recording notification ${notification.id} — status: ${notification.status}, channel: ${notification.channel}`,
    );

    return this.repository.save(logEntry);
  }

  /**
   * Query notification history with optional filters.
   */
  query(filter: NotificationHistoryQuery): NotificationLog[] {
    let results = this.repository.findAll();

    if (filter.recipient) {
      results = results.filter((log) => log.recipient === filter.recipient);
    }
    if (filter.type) {
      results = results.filter((log) => log.type === filter.type);
    }
    if (filter.channel) {
      results = results.filter((log) => log.channel === filter.channel);
    }
    if (filter.status) {
      results = results.filter((log) => log.status === filter.status);
    }
    if (filter.startDate) {
      results = results.filter((log) => log.timestamp >= filter.startDate!);
    }
    if (filter.endDate) {
      results = results.filter((log) => log.timestamp <= filter.endDate!);
    }

    return results;
  }

  /**
   * Get all history entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all history entries of a specific notification type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all history entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get the total count of logged notifications.
   */
  count(): number {
    return this.repository.count();
  }
}

