import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    channel: 'email',
    priority: 'normal',
    status: 'sent',
    createdAt: new Date('2026-01-15T10:00:00Z'),
    sentAt: new Date('2026-01-15T10:00:01Z'),
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let service: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    service = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('record', () => {
    it('should record a notification in the history', () => {
      const notification = makeNotification();
      const log = service.record(notification);

      expect(log.id).toBe('log-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order_confirmation');
      expect(log.status).toBe('sent');
      expect(log.timestamp).toEqual(new Date('2026-01-15T10:00:01Z'));
    });

    it('should use createdAt when sentAt is not present', () => {
      const notification = makeNotification({ sentAt: undefined, status: 'pending' });
      const log = service.record(notification);

      expect(log.timestamp).toEqual(new Date('2026-01-15T10:00:00Z'));
    });

    it('should record failed notifications with error', () => {
      const notification = makeNotification({
        status: 'failed',
        error: 'SMTP timeout',
      });
      const log = service.record(notification);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('SMTP timeout');
    });

    it('should generate sequential log IDs', () => {
      service.record(makeNotification({ id: 'notif-0001' }));
      service.record(makeNotification({ id: 'notif-0002' }));

      expect(service.count()).toBe(2);
      const logs = service.query({});
      expect(logs[0]?.id).toBe('log-0001');
      expect(logs[1]?.id).toBe('log-0002');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      service.record(makeNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        type: 'order_confirmation',
        channel: 'email',
        status: 'sent',
        createdAt: new Date('2026-01-10T10:00:00Z'),
        sentAt: new Date('2026-01-10T10:00:01Z'),
      }));
      service.record(makeNotification({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'welcome',
        channel: 'email',
        status: 'sent',
        createdAt: new Date('2026-01-15T10:00:00Z'),
        sentAt: new Date('2026-01-15T10:00:01Z'),
      }));
      service.record(makeNotification({
        id: 'notif-0003',
        recipient: 'alice@example.com',
        type: 'order_status_update',
        channel: 'webhook',
        status: 'failed',
        error: 'Connection refused',
        createdAt: new Date('2026-01-20T10:00:00Z'),
        sentAt: new Date('2026-01-20T10:00:01Z'),
      }));
    });

    it('should return all logs when no filter is applied', () => {
      expect(service.query({})).toHaveLength(3);
    });

    it('should filter by recipient', () => {
      const results = service.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by type', () => {
      const results = service.query({ type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should filter by channel', () => {
      const results = service.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = service.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      const results = service.query({
        startDate: new Date('2026-01-12T00:00:00Z'),
        endDate: new Date('2026-01-18T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const results = service.query({
        recipient: 'alice@example.com',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      service.record(makeNotification({
        id: 'notif-0001',
        recipient: 'alice@example.com',
        type: 'order_confirmation',
        createdAt: new Date('2026-01-10T10:00:00Z'),
        sentAt: new Date('2026-01-10T10:00:01Z'),
      }));
      service.record(makeNotification({
        id: 'notif-0002',
        recipient: 'bob@example.com',
        type: 'welcome',
        createdAt: new Date('2026-01-15T10:00:00Z'),
        sentAt: new Date('2026-01-15T10:00:01Z'),
      }));
    });

    it('should get by recipient', () => {
      expect(service.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getByRecipient('nobody@example.com')).toHaveLength(0);
    });

    it('should get by type', () => {
      expect(service.getByType('welcome')).toHaveLength(1);
      expect(service.getByType('order_status_update')).toHaveLength(0);
    });

    it('should get by date range', () => {
      const results = service.getByDateRange(
        new Date('2026-01-09T00:00:00Z'),
        new Date('2026-01-11T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
    });

    it('should count logs', () => {
      expect(service.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(service);
      resetNotificationIdCounter();
    });

    it('should log notifications sent via NotificationService', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.count()).toBe(1);
      const logs = service.query({});
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.status).toBe('pending');
    });

    it('should log multiple notifications from different events', async () => {
      const orderEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const welcomeEvent: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(orderEvent);
      await eventBus.emit(welcomeEvent);

      expect(service.count()).toBe(2);
      const aliceLogs = service.getByRecipient('alice@example.com');
      const bobLogs = service.getByRecipient('bob@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(bobLogs).toHaveLength(1);
      expect(bobLogs[0]?.type).toBe('welcome');
    });
  });
});

